// 1. Configuración de la fecha de auditoría
const hoy = new Date('2026-04-13');
const fechaString = hoy.toISOString().split('T')[0]; // Formato YYYY-MM-DD

// 2. Procesamos TODOS los ítems que entran al nodo
return $input.all().map(item => {
    const data = item.json;
    const info = data.info_actual || {};
    const ultimoMov = data.ultimo_movimiento || {};
    const historial = data.historial_estados || [];

    // Cálculos de tiempo
    const dateLastUpdate = new Date(info.last_update);
    const dateWarrantyEnd = new Date(info.warranty_end);

    const diffDays = isNaN(dateLastUpdate.getTime()) 
        ? 0 
        : Math.floor((hoy - dateLastUpdate) / (1000 * 60 * 60 * 24));

    const isWarrantyExpired = !isNaN(dateWarrantyEnd.getTime()) && dateWarrantyEnd < hoy;

    // 3. Identificación de Hallazgos con Evidencia Detallada
    let findings = [];
    let evidencias = [];

    // Inconsistencia de Estado
    const lastStatusInHistory = (historial && historial[0]) ? historial[0].status : null;
    if (lastStatusInHistory && info.status !== lastStatusInHistory) {
        findings.push("Status Mismatch");
        evidencias.push(`Conflicto de Estado: Sistema dice '${info.status}' pero historial marca '${lastStatusInHistory}'`);
    }

    // Inconsistencia de Ubicación
    if (ultimoMov.to_location && info.location !== ultimoMov.to_location) {
        findings.push("Location Mismatch");
        evidencias.push(`Desvío Logístico: Ubicación '${info.location}' no coincide con destino '${ultimoMov.to_location}'`);
    }

    // Reglas de Negocio
    if (isWarrantyExpired) {
        findings.push("Expired Warranty");
        evidencias.push(`Garantía Vencida el ${info.warranty_end}`);
    }

    if (info.status === "In Use" && (!info.assigned_to || info.assigned_to.toLowerCase() === "empty" || info.assigned_to === "")) {
        findings.push("Unassigned User");
        evidencias.push("Activo en uso sin usuario asignado");
    }

    if (info.status === "In Transit" && diffDays > 30) {
        findings.push("Critical Transit");
        evidencias.push(`Tránsito excedido: ${diffDays} días fuera de HUB`);
    }

    if (info.status === "Repair" && diffDays > 90) {
        findings.push("Stalled Repair");
        evidencias.push(`Reparación estancada: ${diffDays} días en taller`);
    }

    // 4. Clasificación de Riesgo
 let nivelRiesgo = "Ninguno";
    if (findings && findings.length > 0) {
        // CRÍTICO: Pérdida de trazabilidad de usuario, tránsito excedido o taller estancado
        if (findings.includes("Unassigned User") || 
            findings.includes("Critical Transit") || 
            findings.includes("Stalled Repair")) {
            nivelRiesgo = "Crítico";
        } 
        // MEDIO: Inconsistencias de datos o ubicación (Location Mismatch)
        else if (findings.includes("Status Mismatch") || 
                 findings.includes("Location Mismatch")) {
            nivelRiesgo = "Medio";
        } 
        // BAJO: Garantías vencidas u otros temas preventivos
        else {
            nivelRiesgo = "Bajo";
        }
    }

    // 5. Retornamos el objeto procesado para el Sheet
    return {
        fecha_auditoria: fechaString,
        asset_id: data.asset_id,
        nivel_riesgo: nivelRiesgo,
        hallazgos_resumen: findings.length > 0 ? findings.join(", ") : "Sin inconsistencias",
        analisis_detallado: evidencias.length > 0 ? evidencias.join(" | ") : "Cumple normativas",
        dias_en_estado: diffDays,
        status_actual: info.status || "N/A",
        location_actual: info.location || "N/A",
        destino_movimiento: ultimoMov.to_location || "N/A",
        usuario_asignado: (info.assigned_to && info.assigned_to !== "empty") ? info.assigned_to : "Sin asignar",
        garantia_vencida: isWarrantyExpired ? "SÍ" : "NO"
    };
});

