const info = $json.info_actual || {};
const historial = $json.historial_estados || [];

// 1. Ordenar el historial por fecha (de más reciente a más antiguo)
const historialOrdenado = [...historial].sort((a, b) => {
  return new Date(b.status_date) - new Date(a.status_date);
});

// 2. Tomar el primer elemento del historial ordenado
const ultimoEstadoReal = historialOrdenado.length > 0 ? historialOrdenado[0].status : info.status;

// 3. Cálculos básicos
const lastUpdate = new Date(info.last_update);
const diffDays = Math.floor((hoy - lastUpdate) / (1000 * 60 * 60 * 24));
const garantiaVencida = new Date(info.warranty_end) < hoy;

return {
  asset_id: $json.asset_id,
  status_actual: info.status,
  ultimo_estado_historial: ultimoEstadoReal, // Ahora sí es el último
  location_actual: info.location,
  destino_movimiento: $json.ultimo_movimiento.to_location,
  user: info.assigned_to === 'empty' ? 'NOT_ASSIGNED' : info.assigned_to,
  days: diffDays,
  is_expired: garantiaVencida
};

