const items = $input.all();

// 1. Identificamos cuál es cuál en el array
// El que tiene 'output' es el de HOY
const hoyData = items.find(i => i.json.output).json;
// El que tiene 'row_number' es el ANTERIOR
const anteriorData = items.find(i => i.json.row_number).json;

// 2. Extraemos y limpiamos los valores para la cuenta
const hoy = hoyData.porcentaje_peligro || 0;
// Reemplazamos coma por punto por si viene como "66,67"
const anteriorRaw = anteriorData["% de riesgo"] || "0";
const anterior = parseFloat(String(anteriorRaw).replace(',', '.'));

// 3. Calculamos la diferencia
const diferencia = (hoy - anterior).toFixed(2);

// 4. Armamos la tendencia
let tendenciaIcono = "⚖️";
let tendenciaMensaje = "Sin cambios";

if (diferencia < 0) {
    tendenciaIcono = "📉";
    tendenciaMensaje = `Mejora del ${Math.abs(diferencia)}%`;
} else if (diferencia > 0) {
    tendenciaIcono = "⚠️";
    tendenciaMensaje = `Incremento del ${diferencia}%`;
}

// 5. Retornamos TODO lo de hoy + la tendencia nueva
return {
    ...hoyData,
    tendencia_visual: `${tendenciaIcono} ${tendenciaMensaje} respecto a la última auditoría.`,
    diferencia_valor: diferencia,
    dato_anterior_referencia: anterior // Opcional, por si querés chequear
};

// 1. Obtenemos los datos que vienen directamente del Merge2
// n8n entrega los datos en un array llamado 'items' (o 'item' según la versión)
const data = items[0].json; 

// 2. Extraemos los valores. 
// Asegurate de que los nombres de las propiedades (total, criticos) 
// coincidan con los que salen del Merge2.
const totalActivos = data.total || 0;
const totalCriticos = data.criticos || 0;

// 3. Calculamos el porcentaje de riesgo
const porcentajeRiesgo = totalActivos > 0 ? ((totalCriticos / totalActivos) * 100).toFixed(2) : 0;

// 4. Generamos la fecha para el histórico
const fechaActual = new Date().toLocaleString("es-AR", {
  timeZone: "America/Argentina/Buenos_Aires",
  hour12: false
});

// 5. Retornamos el objeto estructurado para n8n
return [
  {
    json: {
      "Fecha": fechaActual,
      "Riesgo_Porcentaje": parseFloat(porcentajeRiesgo),
      "Total_Alertas": totalCriticos,
      "Total_Activos": totalActivos
    }
  }
];

const registros = $input.all();

// Ordena de mayor a menor según el número de fila
registros.sort((a, b) => b.json.row_number - a.json.row_number);

// Retorna solo el primero (el más nuevo)
return registros[0].json;

const items = $input.all();
let resultados = { total: 0, vencidos: 0, saludables: 0 };

items.forEach(item => {
    const data = item.json;
    const etiqueta = data["Criticos"];

    // Buscamos dinámicamente la columna que tiene el número (ej: "195")
    // Filtramos las columnas que sabemos que NO son los datos
    const valorKey = Object.keys(data).find(key => 
        key !== "Criticos" && 
        key !== "row_number" && 
        key !== "col_1"
    );

    const valor = parseFloat(data[valorKey]);

    if (etiqueta === "Cantidad assets") resultados.total = valor;
    if (etiqueta === "garantiaVencida") resultados.vencidos = valor;
    if (etiqueta === "Sin riesgo") resultados.saludables = valor;
});

// Cálculos finales
const total = resultados.total || 1; 
const numeroCriticos = total - resultados.saludables;
const porcentaje = Math.round((numeroCriticos / total) * 100);

return {
    total: total,
    vencidos: resultados.vencidos,
    criticos: numeroCriticos,
    porcentaje_peligro: porcentaje
};
